const raw = $('Generate Content (Claude)').item.json.content?.[0]?.text || '';
const asset = $('Pick Today\'s Asset + Topic').item.json.asset;
const brand = $('Pick Today\'s Asset + Topic').item.json.brand;
const platforms = ['twitter', 'instagram', 'linkedin', 'tiktok'];

// Parse out sections — Claude writes them with headers like (1) (2) (3) (4)
const sections = raw.split(/\(\d\)/).filter(s => s.trim());
const results = [];
for (let i = 0; i < platforms.length; i++) {
  results.push({ json: {
    platform: platforms[i],
    asset,
    brand,
    content_type: 'organic',
    content_body: (sections[i] || raw).trim(),
    status: 'pending'
  }});
}
return results;
